const d = $('PG Get Dialog').first().json;

return [{
  json: {
    dialog_id: d.dialog_id,
    ollama_body: {
      model: 'llama3.2:1b',
      stream: false,
      options: {
        num_predict: 500,
        temperature: 0,
        stop: ['\n\nПРОДАВЕЦ', '\nПРОДАВЕЦ:', 'ПОКУПАТЕЛЬ:'],
      },
      messages: [
        {
          role: 'system',
          content: 'Output ONLY one JSON object. Copy structure exactly:\n{"kpi":{"greeting":true,"needs_discovery_score":0.4,"product_offer":true,"product_justification":false,"objection_handling":null,"upsell_attempt":false,"closing_attempt":false,"overall_score":0.5},"errors":[{"code":"WEAK_NEEDS_DISCOVERY","severity":"high","description":"текст","quote":"цитата","seller_quote":null}],"control_loss":[],"trust_loss":[],"client_signals":[],"strengths":[],"recommended_training":"needs_discovery_open_questions","manager_summary":"кратко"}',
        },
        {
          role: 'user',
          content: `Диалог:\n${d.transcript}`,
        },
      ],
    },
  },
}];

const dialog = $('PG Get Dialog').first().json;
let raw = ($input.first().json.message?.content ?? '')
  .replace(/<\|[^|]+\|>/g, '')
  .trim();

const match = raw.match(/\{[\s\S]*\}/);
if (!match) {
  throw new Error('Ollama не вернул JSON. Ответ: ' + raw.slice(0, 300));
}

let text = match[0];
let result;

while (text.length > 0) {
  try {
    result = JSON.parse(text);
    break;
  } catch (e) {
    if (text.endsWith('}')) {
      text = text.slice(0, -1);
      continue;
    }
    throw new Error(`JSON.parse failed: ${e.message}\n---\n${match[0].slice(0, 500)}`);
  }
}

return [{
  json: {
    dialog_id: dialog.dialog_id,
    result,
    model_version: 'llama3.2:1b',
  },
}];
